# DiskStation Monitor — Final frontend TypeScript fix
# Run: Set-ExecutionPolicy Bypass -Scope Process -Force; .\TSFIX2.ps1

$RepoPath = "C:\Users\LionelMosley\Documents\HTML\Synology - DiskStation Monitor"
Set-Location $RepoPath
Write-Host "Applying final frontend fix..." -ForegroundColor Cyan

# frontend/src/main.ts
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "frontend/src/main.ts"
$dir = Split-Path $fullPath -Parent
if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote frontend/src/main.ts" -ForegroundColor Green

# frontend/tsconfig.json
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "frontend/tsconfig.json"
$dir = Split-Path $fullPath -Parent
if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote frontend/tsconfig.json" -ForegroundColor Green

git add frontend/src/main.ts frontend/tsconfig.json
git commit -m "fix: use declare global for window functions — eliminates all TS cast errors"
git push origin main

if ($LASTEXITCODE -eq 0) {
    Write-Host "`n✅ Pushed! This is the final fix — Netlify will now build successfully." -ForegroundColor Green
    Write-Host "   Watch: https://app.netlify.com/projects/diskstation-monitor/deploys" -ForegroundColor Cyan
} else {
    Write-Host "`n❌ Push failed." -ForegroundColor Red
}